public interface INotifier {
  string Send(string message);
}

public class BaseNotifier : INotifier {
  public string Send(string message) => "base:" + message;
}

public abstract class NotifierDecorator : INotifier {
  protected readonly INotifier Inner;
  protected NotifierDecorator(INotifier inner) { Inner = inner; }
  public abstract string Send(string message);
}

public class LoggingNotifierDecorator : NotifierDecorator {
  public LoggingNotifierDecorator(INotifier inner) : base(inner) { }
  public override string Send(string message) => "log|" + Inner.Send(message);
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Decorator_AddsBehaviorWithoutChangingBase() {
  INotifier notifier = new LoggingNotifierDecorator(new BaseNotifier());
  Assert.AreEqual("log|base:hello", notifier.Send("hello"));
}

[TestMethod]
public void BaseNotifier_RemainsUnchanged() {
  INotifier notifier = new BaseNotifier();
  Assert.AreEqual("base:hello", notifier.Send("hello"));
}
